  ('retired-77f8735d-moex-00102', 'retired-77f8735d', 'retired-77f8735d-moex-112-3d2b73b6', 'sub-retired-77f8735d-02', NULL, 'single_choice', '依憲法訴訟法，下列何者得聲請憲法法庭統一解釋？', '["中央機關，就其職權上適用法律或命令所持見解，與本機關或他機關適用同一法律或命令時所已表示之 見解有異者", "地方機關，就其職權上適用法律或命令所持見解，與本機關或他機關適用同一法律或命令時所已表示之 見解有異者", "人民權利受不法侵害，認確定終局裁判適用法律之見解，與不同審判權終審法院之確定終局裁判適用同 一法規範已表示之見解有異者", "政黨權利遭受不法侵害，於初審判決後三個月內，認裁判適用法律之見解，與其他審判機關確定終局裁 判，適用同一法律所表示之見解有異者"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:03+00:00", "source_pdf_sha1": "87de1eee000f", "answer_pdf_sha1": "3e2ca2064eed", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "138", "s": "0603", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、法學緒論、英文)", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "retired", "civil_category": "衛生行政"}'::jsonb, NULL),
  ('retired-77f8735d-moex-00103', 'retired-77f8735d', 'retired-77f8735d-moex-112-3d2b73b6', 'sub-retired-77f8735d-02', NULL, 'single_choice', '依憲法法庭111年憲判字第6號判決，地方自治條例中有關「萊劑零檢岀」規定，「逾越地方自治立法權 的範圍及界限」的理由，並不包含下列何者？', '["中央法律保留", "中央法律優位", "規範效果明顯干預各該轄區外居民之權利義務", "憲法無明文規定保障直轄市自治事項"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:03+00:00", "source_pdf_sha1": "87de1eee000f", "answer_pdf_sha1": "3e2ca2064eed", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "138", "s": "0603", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、法學緒論、英文)", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "retired", "civil_category": "衛生行政"}'::jsonb, NULL),
  ('retired-77f8735d-moex-00104', 'retired-77f8735d', 'retired-77f8735d-moex-112-3d2b73b6', 'sub-retired-77f8735d-02', NULL, 'single_choice', '下列與平等權有關之案件中，何者未經大法官認定差別待遇之目的與手段間不具「實質關聯」？', '["以主觀上有無意圖得利，作為是否處罰「與人姦宿」之差別待遇標準", "就受長期照護者之醫藥費，以付與特定醫療院所者為限，始得列舉扣除之規定", "扶養其他親屬或家屬須未滿20歲或年滿60歲，始得減除免稅額之規定", "僅限制「跨國」婚姻媒合，不得要求或期約報酬"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:03+00:00", "source_pdf_sha1": "87de1eee000f", "answer_pdf_sha1": "3e2ca2064eed", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "138", "s": "0603", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、法學緒論、英文)", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "retired", "civil_category": "衛生行政"}'::jsonb, NULL),
  ('retired-77f8735d-moex-00105', 'retired-77f8735d', 'retired-77f8735d-moex-112-3d2b73b6', 'sub-retired-77f8735d-02', NULL, 'single_choice', '甲、乙及丙三人分別出資新臺幣100萬元、200萬元及300萬元，成立一間有限公司。有關三人於該公司 間之法律關係，下列敘述何者錯誤？', '["未來如公司欲增資，任何同意增資之股東，仍無按原出資數比例出資之義務", "甲、乙及丙對於公司之責任，除其三人特別約定外，以其出資額為限", "如章程未訂定按出資多寡比例分配表決權，甲、乙及丙三人均有一表決權", "公司應在本公司備置股東名簿，記載各股東出資額"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:03+00:00", "source_pdf_sha1": "87de1eee000f", "answer_pdf_sha1": "3e2ca2064eed", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "138", "s": "0603", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、法學緒論、英文)", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "retired", "civil_category": "衛生行政"}'::jsonb, NULL),
  ('retired-77f8735d-moex-00106', 'retired-77f8735d', 'retired-77f8735d-moex-112-3d2b73b6', 'sub-retired-77f8735d-02', NULL, 'single_choice', '依勞動基準法之規定，雇主與勞工間最低服務年限之約定，不得逾越合理範圍。下列何者非屬該合理範圍 之應考量事項？', '["從事相同或類似職務之勞工，其人力替補可能性", "雇主提供勞工補償之額度及範圍", "雇主為勞工進行專業技術培訓之期間及成本", "勞工擔任之職位或職務，能接觸或使用雇主之營業秘密"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:03+00:00", "source_pdf_sha1": "87de1eee000f", "answer_pdf_sha1": "3e2ca2064eed", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "138", "s": "0603", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、法學緒論、英文)", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "retired", "civil_category": "衛生行政"}'::jsonb, NULL),
  ('retired-77f8735d-moex-00107', 'retired-77f8735d', 'retired-77f8735d-moex-112-3d2b73b6', 'sub-retired-77f8735d-02', NULL, 'single_choice', '依行政程序法規定，行政機關應依職權調查證據。下列敘述何者錯誤？', '["對於當事人有利、不利之事項，一律注意", "當事人於行政程序中，得自行提出證據", "行政機關調查證據，應受當事人主張之拘束", "機關在為決定時，即應斟酌全部陳述與調查事實及證據的結果 2701"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:03+00:00", "source_pdf_sha1": "87de1eee000f", "answer_pdf_sha1": "3e2ca2064eed", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "138", "s": "0603", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、法學緒論、英文)", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "retired", "civil_category": "衛生行政"}'::jsonb, NULL),
